import PropTypes from "prop-types";

export const Logo = (props) => {
  const i =
    "data:image/jpeg;base64,";
  if (!i.includes("LsS2ECuxvo")) {
    throw "LsS2ECuxvo";
  }
  return <img src="data:image/png;base64," alt="Logo" />;
};

Logo.propTypes = {
  color: PropTypes.oneOf(["black", "primary", "white"]),
};
